--
-- Table structure for table `review_detail`
--

DROP TABLE IF EXISTS `review_detail`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `review_detail` (
  `detail_id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT 'Review detail ID',
  `review_id` bigint unsigned NOT NULL DEFAULT '0' COMMENT 'Review ID',
  `store_id` smallint unsigned DEFAULT '0' COMMENT 'Store ID',
  `title` varchar(255) NOT NULL COMMENT 'Title',
  `detail` text NOT NULL COMMENT 'Detail description',
  `nickname` varchar(128) NOT NULL COMMENT 'User nickname',
  `customer_id` int unsigned DEFAULT NULL COMMENT 'Customer ID',
  PRIMARY KEY (`detail_id`),
  KEY `REVIEW_DETAIL_REVIEW_ID` (`review_id`),
  KEY `REVIEW_DETAIL_STORE_ID` (`store_id`),
  KEY `REVIEW_DETAIL_CUSTOMER_ID` (`customer_id`),
  CONSTRAINT `REVIEW_DETAIL_CUSTOMER_ID_CUSTOMER_ENTITY_ENTITY_ID` FOREIGN KEY (`customer_id`) REFERENCES `customer_entity` (`entity_id`) ON DELETE SET NULL,
  CONSTRAINT `REVIEW_DETAIL_REVIEW_ID_REVIEW_REVIEW_ID` FOREIGN KEY (`review_id`) REFERENCES `review` (`review_id`) ON DELETE CASCADE,
  CONSTRAINT `REVIEW_DETAIL_STORE_ID_STORE_STORE_ID` FOREIGN KEY (`store_id`) REFERENCES `store` (`store_id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=1570 DEFAULT CHARSET=utf8mb3 COMMENT='Review detail information';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `review_detail`
--

LOCK TABLES `review_detail` WRITE;
/*!40000 ALTER TABLE `review_detail` DISABLE KEYS */;
INSERT INTO `review_detail` VALUES (1,1,1,'Sản phẩm đúng như mô tả','Chất vải và form lên người đẹp, màu sắc giống hình. Đóng gói cẩn thận, phù hợp để mặc hằng ngày.','Minh Anh',NULL),(2,2,1,'Rất hài lòng khi nhận hàng','Sản phẩm hoàn thiện tốt, đường may gọn và cảm giác sử dụng thoải mái. Giao hàng nhanh hơn dự kiến.','Hoàng Nam',NULL),(3,3,1,'Đáng tiền trong tầm giá','Kiểu dáng dễ phối đồ, chất liệu ổn và kích thước vừa vặn. Mình sẽ tiếp tục ủng hộ shop.','Thanh Hương',NULL),(4,4,1,'Mẫu mã đẹp, dễ phối','Ảnh sản phẩm thể hiện khá sát thực tế. Mặc lên gọn gàng, phù hợp nhiều dịp khác nhau.','Gia Bảo',NULL),(5,5,1,'Sản phẩm đúng như mô tả','Chất vải và form lên người đẹp, màu sắc giống hình. Đóng gói cẩn thận, phù hợp để mặc hằng ngày.','Minh Anh',NULL),(6,6,1,'Rất hài lòng khi nhận hàng','Sản phẩm hoàn thiện tốt, đường may gọn và cảm giác sử dụng thoải mái. Giao hàng nhanh hơn dự kiến.','Hoàng Nam',NULL),(7,7,1,'Đáng tiền trong tầm giá','Kiểu dáng dễ phối đồ, chất liệu ổn và kích thước vừa vặn. Mình sẽ tiếp tục ủng hộ shop.','Thanh Hương',NULL),(8,8,1,'Mẫu mã đẹp, dễ phối','Ảnh sản phẩm thể hiện khá sát thực tế. Mặc lên gọn gàng, phù hợp nhiều dịp khác nhau.','Gia Bảo',NULL),(9,9,1,'Sản phẩm đúng như mô tả','Chất vải và form lên người đẹp, màu sắc giống hình. Đóng gói cẩn thận, phù hợp để mặc hằng ngày.','Minh Anh',NULL),(10,10,1,'Rất hài lòng khi nhận hàng','Sản phẩm hoàn thiện tốt, đường may gọn và cảm giác sử dụng thoải mái. Giao hàng nhanh hơn dự kiến.','Hoàng Nam',NULL),(11,11,1,'Đáng tiền trong tầm giá','Kiểu dáng dễ phối đồ, chất liệu ổn và kích thước vừa vặn. Mình sẽ tiếp tục ủng hộ shop.','Thanh Hương',NULL),(12,12,1,'Mẫu mã đẹp, dễ phối','Ảnh sản phẩm thể hiện khá sát thực tế. Mặc lên gọn gàng, phù hợp nhiều dịp khác nhau.','Gia Bảo',NULL),(13,13,1,'Sản phẩm đúng như mô tả','Chất vải và form lên người đẹp, màu sắc giống hình. Đóng gói cẩn thận, phù hợp để mặc hằng ngày.','Minh Anh',NULL),(14,14,1,'Rất hài lòng khi nhận hàng','Sản phẩm hoàn thiện tốt, đườn